using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.IsTrue(_cart.Items.ContainsKey("SKU-001"));
        Assert.AreEqual(2, _cart.Items["SKU-001"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-001"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        _cart.AddItem("SKU-001", 1, 5.00m);
        _cart.AddItem("SKU-001", 3, 5.00m);

        Assert.AreEqual(4, _cart.Items["SKU-001"].Quantity);
    }

    [TestMethod]
    public void AddItem_MultipleSkus_AllPresent()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 2, 2.00m);

        Assert.AreEqual(2, _cart.Items.Count);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_Throws()
    {
        _cart.AddItem(null!, 1, 1.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_Throws()
    {
        _cart.AddItem("", 1, 1.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_ZeroQuantity_Throws()
    {
        _cart.AddItem("SKU-001", 0, 1.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativeQuantity_Throws()
    {
        _cart.AddItem("SKU-001", -1, 1.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativePrice_Throws()
    {
        _cart.AddItem("SKU-001", 1, -5.00m);
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Allowed()
    {
        _cart.AddItem("FREEBIE", 1, 0.00m);
        Assert.AreEqual(0.00m, _cart.Items["FREEBIE"].Price);
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovedFromCart()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    [ExpectedException(typeof(KeyNotFoundException))]
    public void RemoveItem_NonExistentSku_Throws()
    {
        _cart.RemoveItem("MISSING");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveItem_NullSku_Throws()
    {
        _cart.RemoveItem(null!);
    }

    [TestMethod]
    public void RemoveItem_OnlyTargetRemoved_OthersRemain()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 1, 2.00m);
        _cart.RemoveItem("A");

        Assert.IsFalse(_cart.Items.ContainsKey("A"));
        Assert.IsTrue(_cart.Items.ContainsKey("B"));
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 3, 10.00m);
        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsAll()
    {
        _cart.AddItem("A", 2, 5.00m);
        _cart.AddItem("B", 1, 7.50m);

        Assert.AreEqual(17.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemoved()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_StoresCode()
    {
        _cart.ApplyCoupon("SAVE10");
        Assert.AreEqual("SAVE10", _cart.AppliedCoupon);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        _cart.ApplyCoupon("BOGUS");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        _cart.ApplyCoupon("");
    }

    [TestMethod]
    public void ApplyCoupon_ReplacePreviousCoupon()
    {
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual("SAVE20", _cart.AppliedCoupon);
    }

    // ── Coupon + Total integration ───────────────────────────

    [TestMethod]
    public void CalculateTotal_WithSave10_Applies10PercentDiscount()
    {
        _cart.AddItem("A", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_WithSave20_Applies20PercentDiscount()
    {
        _cart.AddItem("A", 2, 50.00m);
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_WithHalf_Applies50PercentDiscount()
    {
        _cart.AddItem("A", 1, 33.33m);
        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(16.67m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_NoCoupon_NoDiscount()
    {
        _cart.AddItem("A", 1, 100.00m);
        Assert.IsNull(_cart.AppliedCoupon);
        Assert.AreEqual(100.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_CouponOnEmptyCart_ReturnsZero()
    {
        _cart.ApplyCoupon("SAVE10");
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }
}

